function solve(prices, strategy, k) {
  const n = prices.length;
  let maxProfit = 0;
  let totalProfit = 0;

  // Calculate the original profit
  for (let i = 0; i < n; i++) {
    totalProfit += strategy[i] * prices[i];
  }
  maxProfit = totalProfit;

  // Try to modify each possible k-length consecutive subarray
  for (let i = 0; i <= n - k; i++) {
    // Calculate the original contribution of the subarray
    let originalContribution = 0;
    for (let j = i; j < i + k; j++) {
      originalContribution += strategy[j] * prices[j];
    }

    // Calculate the new contribution of the subarray after modification
    let newContribution = 0;
    for (let j = i; j < i + k / 2; j++) {
      newContribution += 0 * prices[j];  // hold
    }
    for (let j = i + k / 2; j < i + k; j++) {
      newContribution += 1 * prices[j];  // sell
    }

    // Update the total profit with the new contribution
    const newTotalProfit = totalProfit - originalContribution + newContribution;
    if (newTotalProfit > maxProfit) {
      maxProfit = newTotalProfit;
    }
  }

  return maxProfit;
}
